('additional-maths:8-3-stationary-points-and-curve-sketching:match:8f7151f7', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\frac{dy}{dx} = 0 \\)”?", "options": ["Given as an \\( (x,\\ y) \\) pair", "Local maximum", "Condition for a stationary point", "Local minimum"]}'::jsonb, '{"answer": 2, "explain": "“\\( \\frac{dy}{dx} = 0 \\)” means: Condition for a stationary point"}'::jsonb),
