('additional-maths:8-3-stationary-points-and-curve-sketching:match:16025237', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\frac{d^2y}{dx^2} < 0 \\)”?", "options": ["Maximum point", "Find the \\( y \\)-coordinate", "Minimum point", "Test inconclusive — check the gradient either side"]}'::jsonb, '{"answer": 0, "explain": "“\\( \\frac{d^2y}{dx^2} < 0 \\)” means: Maximum point"}'::jsonb),
